    # Update homepage additively
    idx=site/'index.html'
    section=f'''<!-- GOALOS_PROOF_CARDS_V16_START --><section class="pc-section"><div class="pc-wrap"><div class="pc-kicker">Proof Card Command Center</div><h2 class="pc-title">Proof Cards 001-010</h2><p class="pc-lede">GoalOS turns AI work into proof. AGIALPHA coordinates proof-settled missions. Evidence Dockets make claims auditable. RSI reuses only what proved itself.</p>{cards_grid()}<a class="pc-button" href="proof-cards.html">Open all Proof Cards</a></div></section><!-- GOALOS_PROOF_CARDS_V16_END -->'''
