    site.joinpath('sovereign-rsi-control-plane.html').write_text(full_page('Sovereign RSI','<div class="pc-hero"><div class="pc-kicker">Sovereign RSI</div><h1>Recursive Self-Improvement through proof-backed upgrade rights</h1><p class="pc-lede">The system improves efficiently because unproven artifacts cannot become future operating context.</p></div>'), encoding='utf-8')
